const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

// PostgreSQL connection configuration
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database_name',
  password: 'your_password',
  port: 5432,
});

// Create a table
app.post('/create-table', async (req, res) => {
  try {
    const { tableName, columns } = req.body;
    const query = `CREATE TABLE ${tableName} (${columns.join(', ')})`;
    await pool.query(query);
    res.status(201).send(`Table ${tableName} created successfully`);
  } catch (error) {
    res.status(500).send(error.message);
  }
});

// Read data from a table
app.get('/read-table', async (req, res) => {
  try {
    const { tableName } = req.query;
    const query = `SELECT * FROM ${tableName}`;
    const result = await pool.query(query);
    res.status(200).send(result.rows);
  } catch (error) {
    res.status(500).send(error.message);
  }
});

// Update data in a table
app.put('/update-table', async (req, res) => {
  try {
    const { tableName, setClause, whereClause } = req.body;
    const query = `UPDATE ${tableName} SET ${setClause} WHERE ${whereClause}`;
    await pool.query(query);
    res.status(200).send(`Data updated successfully`);
  } catch (error) {
    res.status(500).send(error.message);
  }
});

// Delete data from a table
app.delete('/delete-table', async (req, res) => {
  try {
    const { tableName, whereClause } = req.body;
    const query = `DELETE FROM ${tableName} WHERE ${whereClause}`;
    await pool.query(query);
    res.status(200).send(`Data deleted successfully`);
  } catch (error) {
    res.status(500).send(error.message);
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});